class ImageProcessingController < ApplicationController
  require "shellwords"
  require "securerandom"
  require "fileutils"

  ALLOWED_FORMATS = %w[jpg jpeg png gif webp tiff bmp].freeze

  def create
    uploaded = params.require(:image)
    format = params.require(:format).to_s.downcase
    size = params[:size].to_s

    unless ALLOWED_FORMATS.include?(format)
      render json: { error: "unsupported format" }, status: :unprocessable_entity
      return
    end

    unless size.blank? || size.match?(/\A\d+x\d+\z/)
      render json: { error: "invalid size" }, status: :unprocessable_entity
      return
    end

    tmp_dir = Rails.root.join("tmp", "image_processing")
    FileUtils.mkdir_p(tmp_dir)

    input_ext = File.extname(uploaded.original_filename.to_s)
    input_path = tmp_dir.join("#{SecureRandom.uuid}#{input_ext}")
    output_path = tmp_dir.join("#{SecureRandom.uuid}.#{format}")

    File.binwrite(input_path, uploaded.read)

    command = ["convert", input_path.to_s]
    command += ["-resize", size] unless size.blank?
    command << output_path.to_s

    success = system(*command)

    unless success && File.exist?(output_path)
      FileUtils.rm_f(input_path)
      FileUtils.rm_f(output_path)
      render json: { error: "conversion failed" }, status: :unprocessable_entity
      return
    end

    send_file output_path,
              filename: "converted.#{format}",
              type: Marcel::MimeType.for(Pathname.new(output_path)),
              disposition: "attachment"
  ensure
    FileUtils.rm_f(input_path) if defined?(input_path) && input_path
    FileUtils.rm_f(output_path) if defined?(output_path) && output_path
  end
end